Figure 2 — Separate data logic from display logic
This example illustrates the principle behind Rule 3: filtering and shared data preparation should occur in reusable reactive objects, while plotting functions should only render the prepared result.

R Shiny
degs &lt;- reactive({
  df &lt;- raw_data()
  req(df)
  df[df$adj.P.Val &lt;= input$deg_pval &
     abs(df$logFC) &gt;= input$deg_lfc, ]
})

output$volcano &lt;- renderPlot({
  df &lt;- degs()
  ggplot(df, aes(logFC, -log10(adj.P.Val))) +
    geom_point()
})


Python Shiny
@reactive.calc
def degs():
    df = raw_data()
    if df is None:
        return None
    return df[
        (df["adj.P.Val"] &lt;= input.deg_pval()) &
        (df["logFC"].abs() &gt;= input.deg_lfc())
    ]

@output
@render.plot
def volcano():
    df = degs()
    if df is None:
        return
    plt.scatter(df["logFC"], -np.log10(df["adj.P.Val"]))
